#region References

using NUnit.Framework;

#endregion

namespace Cornerstone.Generators.UnitTests.Avalonia;

[TestFixture]
public class StyledPropertyTests : GeneratorUnitTest
{
	#region Methods

	[Test]
	public void Styled()
	{
		var input = """
					public partial class Test : CornerstoneControl
					{
						[StyledProperty]
						public partial int Bar { get; set; }
					}
					""";

		// Generated Code - Expected
		var expected = new[]
		{
			"""
			using System;
			using System.Collections.Generic;
			// <auto-generated>
			// Auto-generated by Cornerstone.Generators
			// </auto-generated>
			partial class Test
			{
				public static readonly global::Avalonia.StyledProperty<global::System.Int32> BarProperty = global::Avalonia.AvaloniaProperty.Register<global::Test, global::System.Int32>(nameof(Bar));
				public partial global::System.Int32 Bar
				{
					get => GetValue(BarProperty);
					set => SetValue(BarProperty, value);
				}
			}
			""",
			"""
			// <auto-generated>
			// Auto-generated by Cornerstone.Generators
			// </auto-generated>
			internal static partial class __CornerstoneSourceReflectorInitializer
			{
				[global::System.Runtime.CompilerServices.ModuleInitializer]
				public static void Initialize()
				{
				}
			}
			"""
		};
		// Generated Code - /Expected

		ValidateSource(input, expected);
	}

